import java.nio.charset.StandardCharsets;
import java.util.Scanner;

public class SecureBufferImplementation {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        byte[] inputBytes = userInput.getBytes(StandardCharsets.UTF_8);

        if (inputBytes.length > 10) {
            System.out.println("Input string exceeds buffer size. Please enter a shorter string.");
            return;
        }

        char[] buffer = new char[10];
        for (int i = 0; i < inputBytes.length; i++) {
            buffer[i] = (char) inputBytes[i];
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
